  children: React.ReactNode;
}) {
  return (
    <div className="flex flex-col gap-1">
      <span className="text-[10px] font-semibold uppercase tracking-wider text-muted-foreground">
        {label}
      </span>
      <div className="text-sm">{children}</div>
    </div>
  );
}

function MachineDetailView({
  machine,
  connectCommand,
  deviceOnline,
  relayConnected,
  isBootstrapping,
  onReconnect,
  onRotateKey,
}: {
  machine: Machine;
  connectCommand: string | null;
  deviceOnline: boolean;
  relayConnected: boolean;
  isBootstrapping: boolean;
  onReconnect: () => void;
  onRotateKey: () => void;
}) {
  const [copied, setCopied] = useState(false);

  async function handleCopy() {
    if (!connectCommand) return;
    await navigator.clipboard.writeText(connectCommand);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  }

  const createdDate = machine.createdAt
    ? new Date(machine.createdAt).toLocaleDateString("en-US", {
        day: "numeric",
        month: "short",
        year: "numeric",
      })
    : "—";

  const displayTitle = machine.hostName ?? machine.name;

  return (
    <div className="flex flex-col min-h-full">
      {relayConnected && !deviceOnline && (
        <div className="flex items-center justify-between px-6 py-2.5 bg-amber-50 border-b border-amber-100 text-sm">
          <span className="text-amber-800">{displayTitle} is offline</span>
          <Button size="sm" variant="outline" onClick={onReconnect} disabled={isBootstrapping}>
            Reconnect
          </Button>
        </div>
      )}

      <div className="px-8 py-8 flex flex-col gap-8 max-w-4xl w-full">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-3">
            <IconDeviceDesktop className="size-5 shrink-0" />
            <h1 className="text-lg font-semibold">{displayTitle}</h1>
            <div className="flex items-center gap-1.5">
              <span
                className={cn(
                  "size-2 rounded-full",
                  deviceOnline ? "bg-green-500" : "bg-muted-foreground/30"
                )}
              />
              <span className="text-sm text-muted-foreground">
                {deviceOnline ? "Online" : "Offline"}
              </span>
            </div>
          </div>
          <Button size="sm" variant="outline" onClick={onReconnect} disabled={isBootstrapping}>
            <IconRefresh className="size-4" />
            {isBootstrapping ? "Connecting..." : "Reconnect"}
          </Button>
        </div>

        <div className="grid grid-cols-2 sm:grid-cols-3 gap-x-8 gap-y-4 pb-6 border-b">
          <InfoBlock label="Hostname">{machine.hostName ?? "—"}</InfoBlock>
          <InfoBlock label="Runtimes">
            {machine.runtimes && machine.runtimes.length > 0 ? (
              <div className="flex flex-wrap gap-1">
                {machine.runtimes.map((r) => (
                  <span
                    key={r}
                    className="px-1.5 py-0.5 rounded bg-muted text-xs font-mono"
