                  Done
                </Button>
              </DialogFooter>
            </div>
          )}
        </DialogContent>
      </Dialog>

      <Dialog open={userDialogOpen} onOpenChange={setUserDialogOpen}>
        <DialogContent className="sm:max-w-sm">
          <DialogHeader>
            <DialogTitle>{userName}</DialogTitle>
          </DialogHeader>
          <p className="text-sm text-muted-foreground">{userEmail}</p>
          <DialogFooter>
            <SignOutButton />
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </SidebarProvider>
  );
}
